qry:select.qry:xquery:
for $r in sql(' SELECT ORG09_GR_CCOSTO.c_grupo_ccosto , sum(LIQ20_CCOSTO_CONC.n_valor) as valor FROM PER02_PERSONAL_EMP, LIQ19_LIQUIDACION, LIQ19_EJECUCIONES, LIQ99_LIQUIDACION, LIQ99_RECIBOS, LIQ20_TOT_LIQ_PER, LIQ20_CCOSTO_CONC, ORG08_CS_COSTO, ORG09_GR_CCOSTO, LIQ20_CONC_LIQ_PER, LIQ14_CONCEPTOS, LIQ96_CONCEPTOS WHERE LIQ19_LIQUIDACION.oi_empresa = {#PARAMIN:@oi_empresaFIL} AND PER02_PERSONAL_EMP.oi_empresa = {#PARAMIN:@oi_empresaFIL} AND LIQ19_LIQUIDACION.e_periodo = {#PARAMIN:@e_periodoFIL} {%? (#PARAMIN:@oi_liquidacionFIL!='') {% and LIQ19_LIQUIDACION.oi_liquidacion = {%= #PARAMIN:@oi_liquidacionFIL %} %} {% %} %} AND LIQ99_LIQUIDACION.c_estado = \'F\' AND LIQ20_CONC_LIQ_PER.n_valor != 0 and ORG09_GR_CCOSTO.c_grupo_ccosto = {#SOURCE:@gcc} {%? (#SOURCE:@oi_concepto!='') {% AND LIQ14_CONCEPTOS.oi_concepto = {#SOURCE:@oi_concepto} %} {% %} %} {%? (#SOURCE:@oi_tipo_concepto!='') {% AND LIQ14_CONCEPTOS.oi_tipo_concepto = {#SOURCE:@oi_tipo_concepto} %} {% %} %} {%? (#SOURCE:@oi_personal_emp!='') {% AND PER02_PERSONAL_EMP.oi_personal_emp = {#SOURCE:@oi_personal_emp} %} {% %} %} {%? (string(#LISTAPERS:ROWS/ROW/@id)!='') {% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#LISTAPERS:ROWS/ROW/@id) %}) %} {% %} %} {%? (#PARAMIN:@oi_centro_costoFIL!='') {% and ORG08_CS_COSTO.c_centro_costo = {#PARAMIN_CCOSTO:@c_filtro_costo} %} {% %} %}
and LIQ20_CCOSTO_CONC.c_centro_costo = ORG08_CS_COSTO.c_centro_costo AND ORG09_GR_CCOSTO.oi_grupo_ccosto = ORG08_CS_COSTO.oi_grupo_ccosto AND LIQ19_LIQUIDACION.oi_liquidacion = LIQ19_EJECUCIONES.oi_liquidacion AND LIQ19_EJECUCIONES.oi_liquidacion_ddo = LIQ99_LIQUIDACION.oi_liquidacion_ddo AND LIQ99_LIQUIDACION.oi_liquidacion_ddo = LIQ99_RECIBOS.oi_liquidacion_ddo AND LIQ99_RECIBOS.e_numero_legajo = PER02_PERSONAL_EMP.e_numero_legajo AND LIQ99_RECIBOS.oi_tot_liq_per = LIQ20_TOT_LIQ_PER.oi_tot_liq_per AND LIQ20_TOT_LIQ_PER.oi_tot_liq_per = LIQ20_CONC_LIQ_PER.oi_tot_liq_per AND LIQ20_CONC_LIQ_PER.oi_concepto_ddo = LIQ96_CONCEPTOS.oi_concepto_ddo AND LIQ96_CONCEPTOS.c_concepto = LIQ14_CONCEPTOS.c_concepto AND LIQ20_CONC_LIQ_PER.oi_conc_liq_per = LIQ20_CCOSTO_CONC.oi_conc_liq_per GROUP BY ORG09_GR_CCOSTO.c_grupo_ccosto
')/ROWS/ROW
